SELECT *
FROM Golfer
WHERE age = “Senior”;

SELECT scotGolfNo, club
FROM Golfer
WHERE age = “Junior”;

SELECT forename, club
FROM Golfer
WHERE handicap < 6;

SELECT Name, Certificate
FROM Movies
WHERE Length >= 110;

SELECT Name, Star
FROM Movies
WHERE Length <= 120;

SELECT forename, surname
FROM Result
WHERE test1 > 50;

SELECT *
FROM Result
WHERE test2 = 90;

SELECT *
FROM Result
WHERE test1 >= 50 AND test2 >= 50;

SELECT *
FROM Result
WHERE test1 > 50 OR test2 > 50;

SELECT orderID, type, collection
FROM Order
ORDER BY type DESC;

SELECT contractCode, contractLength, phoneType, storage
FROM contract
ORDER BY storage ASC, contractLength DESC;

SELECT *
FROM Class
ORDER BY sessionBlock DESC, time ASC;

SELECT Artists.name, Labels.labelName
FROM Artists, Labels
WHERE Artists.labelID = Labels.labelID;

UPDATE CanteenInventory
SET Quantity = 20
WHERE ItemID = “CI002”;

UPDATE SUPClasses
SET InstructorID= “SUP03”, MaxParticipants = 10
WHERE InstructorID= “SUP01”;
